def search_hadith(substring, limit=5):
    res = []
    for i, h in enumerate(hadith_data):
        text = h.get('hadithTxt') or h.get('Matn') or ''
        if substring in text:
            res.append(text[:2000])
            if len(res)>=limit:
                break
    return res

